from google.cloud import storage, firestore, pubsub_v1
import json
import os

def gcs_to_firestore_pubsub(event, context):
    # Initialize clients
    storage_client = storage.Client()
    firestore_client = firestore.Client()
    publisher = pubsub_v1.PublisherClient()
    
    # Get file information from the event
    bucket_name = event['bucket']
    file_name = event['name']
    
    # Download the file from Cloud Storage
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    file_content = blob.download_as_text()
    
    # Process the file (assuming it's JSON for example)
    data = json.loads(file_content)
    
    # Write to Firestore
    doc_ref = firestore_client.collection('your_collection').document(file_name)
    doc_ref.set(data)
    
    # Publish to Pub/Sub
    topic_name = 'projects/your-project-id/topics/your-topic-name'
    future = publisher.publish(topic_name, json.dumps(data).encode('utf-8'), filename=file_name)
    print(f'Published message ID: {future.result()}')